import { CommonModule } from '@angular/common';
import {
  AfterViewInit,
  Component,
  DestroyRef,
  ElementRef,
  Input,
  OnDestroy,
  ViewChild,
  inject
} from '@angular/core';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';
import { FormBuilder, ReactiveFormsModule, Validators } from '@angular/forms';
import { RouterLink } from '@angular/router';
import { finalize } from 'rxjs';
import { BrowserContextService } from '../../core/services/browser-context.service';
import {
  ContactRequestPayload,
  ContactService,
  ContactSubmissionError
} from '../../core/services/contact.service';
import { TurnstileApi, TurnstileScriptService } from '../../core/services/turnstile-script.service';
import { SiteLanguage } from '../../interfaces/language.interface';
import { SiteContactFormConfig } from '../../interfaces/site-config.interface';

type ContactField = 'name' | 'email' | 'subject' | 'message';
type StatusKind = 'success' | 'error';

interface SubmittedMessageSummary {
  name: string;
  email: string;
  subject: string;
  message: string;
}

@Component({
  selector: 'app-contact-form',
  standalone: true,
  imports: [CommonModule, ReactiveFormsModule, RouterLink],
  templateUrl: './contact-form.component.html',
  styleUrl: './contact-form.component.sass'
})
export class ContactFormComponent implements AfterViewInit, OnDestroy {
  private readonly fb = inject(FormBuilder);
  private readonly destroyRef = inject(DestroyRef);
  private readonly contactService = inject(ContactService);
  private readonly turnstileScriptService = inject(TurnstileScriptService);
  private readonly browserContextService = inject(BrowserContextService);

  @Input({ required: true }) language!: SiteLanguage;
  @Input({ required: true }) config!: SiteContactFormConfig;

  @ViewChild('turnstileContainer') private turnstileContainer?: ElementRef<HTMLDivElement>;
  @ViewChild('statusMessage') private statusMessage?: ElementRef<HTMLElement>;

  protected sending = false;
  protected turnstileToken = '';
  protected turnstileError = '';
  protected statusKind: StatusKind | null = null;
  protected statusMessageText = '';
  protected widgetReady = false;
  protected submittedMessage: SubmittedMessageSummary | null = null;

  protected readonly form = this.fb.nonNullable.group({
    name: ['', [Validators.required, Validators.maxLength(120)]],
    email: ['', [Validators.required, Validators.email, Validators.maxLength(254)]],
    subject: ['', [Validators.required, Validators.maxLength(160)]],
    message: ['', [Validators.required, Validators.minLength(20), Validators.maxLength(4000)]]
  });

  private turnstileApi?: TurnstileApi;
  private widgetId: string | null = null;

  protected get title(): string {
    return this.language === 'it' ? 'Scrivimi' : 'Write to me';
  }

  protected get intro(): string {
    return this.language === 'it'
      ? 'Per informazioni su opere, visite in studio o commissioni, compila il modulo.'
      : 'For information about artworks, studio visits or commissions, complete the form.';
  }

  protected get submitLabel(): string {
    if (this.sending) {
      return this.language === 'it' ? 'Invio in corso...' : 'Sending...';
    }

    return this.language === 'it' ? 'Invia messaggio' : 'Send message';
  }

  protected get privacyNotice(): string {
    return this.language === 'it'
      ? 'I dati inseriti saranno utilizzati esclusivamente per rispondere alla richiesta.'
      : 'The data entered will be used exclusively to respond to your request.';
  }

  protected get turnstileLabel(): string {
    return this.language === 'it'
      ? 'Verifica anti-spam'
      : 'Anti-spam verification';
  }

  protected get isConfigured(): boolean {
    return this.config.enabled
      && !!this.config.contactApiUrl.trim()
      && !!this.config.contactSiteId.trim()
      && !!this.config.turnstileSiteKey.trim();
  }

  protected get canSubmit(): boolean {
    return !this.sending && this.form.valid && !!this.turnstileToken && this.isConfigured;
  }

  protected get showTurnstileRetry(): boolean {
    return !!this.turnstileError && !this.sending;
  }

  ngAfterViewInit(): void {
    if (!this.isConfigured || !this.browserContextService.isBrowser()) {
      if (!this.isConfigured) {
        this.setStatus('error', this.language === 'it'
          ? 'Il servizio contatti non è ancora configurato.'
          : 'The contact service is not configured yet.');
      }

      return;
    }

    void this.initializeTurnstile();
  }

  ngOnDestroy(): void {
    this.destroyTurnstileWidget();
  }

  protected fieldLabel(field: ContactField): string {
    const labels = {
      it: {
        name: 'Nome',
        email: 'Email',
        subject: 'Oggetto',
        message: 'Messaggio'
      },
      en: {
        name: 'Name',
        email: 'Email',
        subject: 'Subject',
        message: 'Message'
      }
    };

    return labels[this.language][field];
  }

  protected fieldError(field: ContactField): string {
    const control = this.form.controls[field];

    if (!control.touched || !control.errors) {
      return '';
    }

    if (control.errors['required']) {
      return this.language === 'it'
        ? 'Questo campo è obbligatorio.'
        : 'This field is required.';
    }

    if (control.errors['email']) {
      return this.language === 'it'
        ? 'Inserisci un indirizzo email valido.'
        : 'Enter a valid email address.';
    }

    if (control.errors['minlength']) {
      return this.language === 'it'
        ? 'Il messaggio è troppo breve.'
        : 'The message is too short.';
    }

    if (control.errors['maxlength']) {
      return this.language === 'it'
        ? 'Il contenuto supera la lunghezza consentita.'
        : 'The content exceeds the allowed length.';
    }

    return this.language === 'it'
      ? 'Controlla il valore inserito.'
      : 'Check the value entered.';
  }

  protected hasFieldError(field: ContactField): boolean {
    return !!this.fieldError(field);
  }

  protected controlId(field: ContactField): string {
    return `contact-${field}`;
  }

  protected errorId(field: ContactField): string {
    return `contact-${field}-error`;
  }

  protected submit(): void {
    this.form.markAllAsTouched();
    this.turnstileError = '';
    this.clearStatus();

    if (!this.isConfigured) {
      this.setStatus('error', this.language === 'it'
        ? 'Il servizio contatti non è disponibile in questo momento.'
        : 'The contact service is currently unavailable.');
      return;
    }

    if (this.form.invalid) {
      return;
    }

    if (!this.turnstileToken) {
      this.turnstileError = this.language === 'it'
        ? 'Completa la verifica anti-spam prima di inviare il messaggio.'
        : 'Complete the anti-spam verification before sending your message.';
      return;
    }

    const rawValue = this.form.getRawValue();
    const payload: ContactRequestPayload = {
      siteId: this.config.contactSiteId.trim(),
      name: rawValue.name.trim(),
      email: rawValue.email.trim(),
      subject: rawValue.subject.trim(),
      message: rawValue.message.trim(),
      pageUrl: this.browserContextService.getCurrentUrl(),
      turnstileToken: this.turnstileToken
    };

    this.sending = true;

    this.contactService.submitContact(this.config, payload).pipe(
      finalize(() => {
        this.sending = false;
      }),
      takeUntilDestroyed(this.destroyRef)
    ).subscribe({
      next: () => {
        this.submittedMessage = {
          name: payload.name,
          email: payload.email,
          subject: payload.subject ?? '',
          message: payload.message
        };
        this.form.reset({
          name: '',
          email: '',
          subject: '',
          message: ''
        });
        this.turnstileError = '';
        this.destroyTurnstileWidget();
        this.setStatus(
          'success',
          this.language === 'it'
            ? 'Ti risponderò appena possibile, solitamente entro 24 ore lavorative.'
            : 'I will reply as soon as possible, usually within 24 business hours.'
        );
      },
      error: (error: unknown) => {
        const submissionError = error instanceof ContactSubmissionError
          ? error
          : new ContactSubmissionError('server', 'Unexpected submission error');

        if (submissionError.kind === 'turnstile') {
          this.turnstileError = this.language === 'it'
            ? 'La verifica anti-spam non è valida. Riprova.'
            : 'The anti-spam verification is not valid. Please try again.';
          this.resetTurnstileWidget();
        }

        this.setStatus('error', this.userMessageForError(submissionError));
      }
    });
  }

  private async initializeTurnstile(): Promise<void> {
    try {
      this.turnstileApi = await this.turnstileScriptService.load();
      this.renderTurnstileWidget();
    } catch {
      this.widgetReady = false;
      this.turnstileError = this.language === 'it'
        ? 'La verifica anti-spam non è disponibile. Riprova più tardi.'
        : 'The anti-spam verification is unavailable. Please try again later.';
      this.setStatus('error', this.turnstileError);
    }
  }

  private renderTurnstileWidget(): void {
    if (!this.turnstileApi || !this.turnstileContainer?.nativeElement || this.widgetId) {
      return;
    }

    this.widgetId = this.turnstileApi.render(this.turnstileContainer.nativeElement, {
      sitekey: this.config.turnstileSiteKey.trim(),
      callback: (token: string) => {
        this.turnstileToken = token;
        this.turnstileError = '';
      },
      'expired-callback': () => {
        this.turnstileToken = '';
        this.turnstileError = this.language === 'it'
          ? 'La verifica anti-spam è scaduta. Eseguila di nuovo.'
          : 'The anti-spam verification has expired. Please complete it again.';
        this.resetTurnstileWidget();
      },
      'error-callback': () => {
        this.turnstileToken = '';
        this.turnstileError = this.language === 'it'
          ? 'Errore nella verifica anti-spam. Riprova.'
          : 'Error during anti-spam verification. Please try again.';
      }
    });
    this.widgetReady = true;
  }

  protected retryTurnstileWidget(): void {
    this.turnstileError = '';
    this.resetTurnstileWidget();
  }

  private resetTurnstileWidget(): void {
    this.turnstileToken = '';

    if (!this.turnstileApi || !this.widgetId) {
      return;
    }

    this.turnstileApi.reset(this.widgetId);
  }

  private destroyTurnstileWidget(): void {
    if (this.turnstileApi && this.widgetId) {
      this.turnstileApi.remove(this.widgetId);
    }

    this.widgetId = null;
    this.widgetReady = false;
    this.turnstileToken = '';
  }

  private clearStatus(): void {
    this.statusKind = null;
    this.statusMessageText = '';
  }

  private setStatus(kind: StatusKind, message: string): void {
    this.statusKind = kind;
    this.statusMessageText = message;

    setTimeout(() => {
      this.statusMessage?.nativeElement.focus();
    });
  }

  private userMessageForError(error: ContactSubmissionError): string {
    if (error.kind === 'validation') {
      return this.language === 'it'
        ? 'Controlla i dati inseriti e riprova.'
        : 'Check the information entered and try again.';
    }

    if (error.kind === 'turnstile') {
      return this.language === 'it'
        ? 'La verifica anti-spam non è andata a buon fine.'
        : 'The anti-spam verification did not complete successfully.';
    }

    if (error.kind === 'network') {
      return this.language === 'it'
        ? 'Connessione non disponibile. Riprova tra poco.'
        : 'Connection unavailable. Please try again shortly.';
    }

    if (error.kind === 'unavailable') {
      return this.language === 'it'
        ? 'Il servizio contatti non è disponibile in questo momento.'
        : 'The contact service is currently unavailable.';
    }

    return this.language === 'it'
      ? 'Invio non riuscito. Puoi usare il contatto email diretto qui sotto.'
      : 'Sending failed. You can use the direct email contact below.';
  }
}
