import { HttpClient, HttpErrorResponse } from '@angular/common/http';
import { Injectable } from '@angular/core';
import { Observable, catchError, map, throwError } from 'rxjs';
import { SiteContactFormConfig } from '../../interfaces/site-config.interface';

export interface ContactRequestPayload {
  siteId: string;
  name: string;
  email: string;
  phone?: string;
  subject?: string;
  message: string;
  artworkId?: number;
  artworkTitle?: string;
  pageUrl?: string;
  turnstileToken: string;
}

export interface ContactSuccessResponse {
  status: 'received';
  publicId: string;
}

interface ContactErrorResponse {
  error?: {
    code?: string;
    message?: string;
  };
}

export type ContactSubmissionErrorKind = 'validation' | 'turnstile' | 'network' | 'server' | 'unavailable';

export class ContactSubmissionError extends Error {
  constructor(
    readonly kind: ContactSubmissionErrorKind,
    message: string
  ) {
    super(message);
    this.name = 'ContactSubmissionError';
  }
}

@Injectable({
  providedIn: 'root'
})
export class ContactService {
  constructor(private readonly http: HttpClient) {}

  submitContact(
    config: SiteContactFormConfig,
    payload: ContactRequestPayload
  ): Observable<ContactSuccessResponse> {
    if (
      !config.enabled
      || !config.contactApiUrl.trim()
      || !config.contactSiteId.trim()
      || !config.turnstileSiteKey.trim()
    ) {
      return throwError(() => new ContactSubmissionError('unavailable', 'Contact form unavailable'));
    }

    return this.http.post<ContactSuccessResponse | ContactErrorResponse>(config.contactApiUrl, payload).pipe(
      map((response) => {
        if ((response as ContactSuccessResponse).status === 'received') {
          return response as ContactSuccessResponse;
        }

        throw new ContactSubmissionError('server', 'Unexpected contact service response');
      }),
      catchError((error: unknown) => throwError(() => this.mapSubmissionError(error)))
    );
  }

  private mapSubmissionError(error: unknown): ContactSubmissionError {
    if (error instanceof ContactSubmissionError) {
      return error;
    }

    if (!(error instanceof HttpErrorResponse)) {
      return new ContactSubmissionError('server', 'Unknown contact service error');
    }

    if (error.status === 0) {
      return new ContactSubmissionError('network', 'Network error');
    }

    const code = (error.error as ContactErrorResponse | null)?.error?.code;

    if (code === 'validation_error' || error.status === 400) {
      if (code === 'turnstile_verification_failed') {
        return new ContactSubmissionError('turnstile', 'Turnstile verification failed');
      }

      return new ContactSubmissionError('validation', 'Validation error');
    }

    if (code === 'turnstile_verification_failed' || code === 'turnstile_not_configured') {
      return new ContactSubmissionError('turnstile', 'Turnstile verification failed');
    }

    if (error.status >= 500) {
      return new ContactSubmissionError('server', 'Server error');
    }

    return new ContactSubmissionError('server', 'Contact request failed');
  }
}
