import { AsyncPipe } from '@angular/common';
import { Component, inject } from '@angular/core';
import { ActivatedRoute } from '@angular/router';
import { combineLatest, map, tap } from 'rxjs';
import { ContactFormComponent } from '../../components/contact-form/contact-form.component';
import { HeroComponent } from '../../components/hero/hero.component';
import { NewsletterComponent } from '../../components/newsletter/newsletter.component';
import { SocialLinksComponent } from '../../components/social-links/social-links.component';
import { LanguageService } from '../../services/language.service';
import { SeoService } from '../../services/seo.service';
import { SiteService } from '../../services/site.service';
import { CONTACTS_CONTENT } from '../../../content/contacts.content';
import { RevealOnScrollDirective } from '../../directives/reveal-on-scroll.directive';

@Component({
  selector: 'app-contacts-page',
  standalone: true,
  imports: [AsyncPipe, HeroComponent, ContactFormComponent, NewsletterComponent, SocialLinksComponent, RevealOnScrollDirective],
  templateUrl: './contacts.page.html',
  styleUrl: './contacts.page.sass'
})
export class ContactsPage {
  private readonly siteService = inject(SiteService);
  private readonly languageService = inject(LanguageService);
  private readonly seoService = inject(SeoService);
  private readonly route = inject(ActivatedRoute);

  protected readonly vm$ = combineLatest([
    this.siteService.getSiteConfig(),
    this.siteService.getPagesConfig()
  ]).pipe(
    map(([siteConfig, pagesConfig]) => {
      const language = this.languageService.getRouteLanguage(this.route.snapshot);

      return {
        siteConfig,
        pagesConfig,
        language,
        content: CONTACTS_CONTENT
      };
    }),
    tap(({ siteConfig, pagesConfig, language }) => {
      this.seoService.applyLocalizedAlternates(
        siteConfig.domain,
        this.route.snapshot,
        undefined,
        siteConfig.defaultLanguage
      );

      this.seoService.applyPageMetadata({
        title: language === 'en' ? `Contact | ${siteConfig.artistName}` : `Contatti | ${siteConfig.artistName}`,
        description:
          language === 'en'
            ? `Contact ${siteConfig.artistName} for availability, commissions and studio conversations.`
            : `Contatta ${siteConfig.artistName} per disponibilita', commissioni e dialogo con lo studio.`,
        url: `${siteConfig.domain}${this.languageService.buildLocalizedPath(language, 'contacts')}`,
        image: `${siteConfig.domain}${pagesConfig.contacts.heroImage}`,
        siteName: siteConfig.artistName,
        language
      });
    })
  );
}
